import { d3_max } from '../../../core/d3-constants';
import { ScaleRegistry } from '../../../scale/scale-registry';
import { MeasureText } from '../../../label/datalabel-measure';
import { labelCorrection } from '../../evaluators/correction/correction-adapter'; // TODO: Remove at end of Code modularization
import { _modularized } from '../../../core/zcconf';
import { invokeFunction } from '../../../utils/zcutils';

export function evalLabelCorrection(_) {
    let _scale = this,
        { data, config, renderMode, accessor, padding, measure } = _,
        bbs = MeasureText(data, { config, renderMode, accessor });

    let bound = d3_max(bbs, bb => padding + invokeFunction(measure, bb));
    if (!_modularized.scaleCorrection) {
        return labelCorrection(_scale, bound);
    }
    return bound || 0;
}

ScaleRegistry.add('font-correction-evaluator', evalLabelCorrection);
ScaleRegistry.add('label-correction-evaluator', evalLabelCorrection);
